  const [shortcutsOpen, setShortcutsOpen] = useState(false);

  useEffect(() => {
    const handler = () => setShortcutsOpen(v => !v);
    window.addEventListener('mp3king:toggle-shortcuts', handler);
    return () => window.removeEventListener('mp3king:toggle-shortcuts', handler);
  }, []);

